Let me provide you with the complete Nextra setup files that you can implement step-by-step:

## 🚀 **Complete Nextra Setup for nioeze-website**

I'll provide all the files you need to create:

---

### **1. Updated `next.config.ts`**

```typescript name=next.config.ts
import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  pageExtensions: ["js", "jsx", "ts", "tsx", "md", "mdx"],
  webpack: (config) => {
    config.resolve.fallback = {
      ...config.resolve.fallback,
      fs: false,
    };
    return config;
  },
};

export default nextConfig;
```

---

### **2. Updated `package.json`**

```json name=package.json
{
  "name": "nioeze-website",
  "version": "0.1.0",
  "private": true,
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start",
    "lint": "next lint",
    "docs:dev": "next dev",
    "docs:build": "next build"
  },
  "dependencies": {
    "@vercel/speed-insights": "^2.0.0",
    "next": "^15.1.5",
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "nextra": "^2.13.0",
    "nextra-theme-docs": "^2.13.0",
    "next-mdx-remote": "^5.0.0",
    "gray-matter": "^4.0.3"
  },
  "devDependencies": {
    "@types/node": "^22",
    "@types/react": "^19",
    "@types/react-dom": "^19",
    "eslint": "^9",
    "eslint-config-next": "^15.1.5",
    "typescript": "^5"
  }
}
```

---

### **3. Create `app/docs/layout.tsx`**

```typescript name=app/docs/layout.tsx
import React from 'react';
import Link from 'next/link';
import './docs.css';

type DocsSidebarItem = {
  title: string;
  href: string;
  items?: DocsSidebarItem[];
};

const sidebar: DocsSidebarItem[] = [
  { title: 'Overview', href: '/docs' },
  {
    title: 'Getting Started',
    href: '/docs/getting-started',
    items: [
      { title: 'Introduction', href: '/docs/getting-started' },
      { title: 'Setup', href: '/docs/getting-started/setup' },
    ],
  },
  {
    title: 'Services',
    href: '/docs/services',
    items: [
      { title: 'Overview', href: '/docs/services' },
      { title: 'Digital Tools & Automation', href: '/docs/services/digital-tools' },
      { title: 'Branding & Creative', href: '/docs/services/branding' },
      { title: 'AI Guidance & Training', href: '/docs/services/ai-guidance' },
      { title: 'Business Setup', href: '/docs/services/business-setup' },
    ],
  },
  {
    title: 'Academy',
    href: '/docs/academy',
    items: [
      { title: 'Overview', href: '/docs/academy' },
      { title: 'Learning Modules', href: '/docs/academy/modules' },
      { title: 'Progress Tracking', href: '/docs/academy/progress' },
    ],
  },
  {
    title: 'FAQ',
    href: '/docs/faq',
  },
];

export default function DocsLayout({ children }: { children: React.ReactNode }) {
  return (
    <div className="docs-layout">
      <aside className="docs-sidebar">
        <div className="sidebar-header">
          <h2>NIOEZE Docs</h2>
        </div>
        <nav className="sidebar-nav">
          {sidebar.map((item) => (
            <div key={item.href} className="nav-item">
              <Link href={item.href} className="nav-link">
                {item.title}
              </Link>
              {item.items && (
                <div className="nav-submenu">
                  {item.items.map((subitem) => (
                    <Link key={subitem.href} href={subitem.href} className="nav-sublink">
                      {subitem.title}
                    </Link>
                  ))}
                </div>
              )}
            </div>
          ))}
        </nav>
      </aside>
      <main className="docs-content">
        <div className="docs-main">
          {children}
        </div>
        <footer className="docs-footer">
          <p>&copy; 2026 NIOEZE. All rights reserved.</p>
          <p>
            <a href="mailto:nioeze@yahoomail.com">Contact Us</a> | 
            <a href="https://github.com/khaddiiqido-byte/nioeze-website">GitHub</a>
          </p>
        </footer>
      </main>
    </div>
  );
}
```

