## **Step 3: Create `app/docs/layout.tsx`**

```typescript name=app/docs/layout.tsx
import React from 'react';
import Link from 'next/link';
import './docs.css';

type DocsSidebarItem = {
  title: string;
  href: string;
  items?: DocsSidebarItem[];
};

const sidebar: DocsSidebarItem[] = [
  { title: 'Overview', href: '/docs' },
  { title: 'Getting Started', href: '/docs/getting-started' },
  { title: 'Services', href: '/docs/services' },
  { title: 'Academy', href: '/docs/academy' },
  { title: 'FAQ', href: '/docs/faq' },
];

export default function DocsLayout({ children }: { children: React.ReactNode }) {
  return (
    <div className="docs-layout">
      <aside className="docs-sidebar">
        <div className="sidebar-header">
          <h2>📚 NIOEZE Docs</h2>
        </div>
        <nav className="sidebar-nav">
          {sidebar.map((item) => (
            <div key={item.href} className="nav-item">
              <Link href={item.href} className="nav-link">
                {item.title}
              </Link>
            </div>
          ))}
        </nav>
      </aside>
      <main className="docs-content">
        <div className="docs-main">
          {children}
        </div>
        <footer className="docs-footer">
          <p>&copy; 2026 NIOEZE. All rights reserved.</p>
          <p>
            <a href="mailto:nioeze@yahoomail.com">Contact Us</a> | 
            <a href="https://github.com/khaddiiqido-byte/nioeze-website">GitHub</a>
          </p>
        </footer>
      </main>
    </div>
  );
}
```

