'use client';

import { useState } from 'react';

export default function FAQPage() {
  const [openItems, setOpenItems] = useState<number[]>([]);

  const toggleItem = (index: number) => {
    setOpenItems(prev =>
      prev.includes(index)
        ? prev.filter(i => i !== index)
        : [...prev, index]
    );
  };

  const faqCategories = [
    {
      category: 'General',
      items: [
        { q: 'What is NIOEZE?', a: 'NIOEZE is a human-centered design and digital solutions platform offering services in AI, education, branding, and digital innovation with a focus on clarity and long-term value.' },
        { q: 'How do I get started with NIOEZE?', a: 'You can get started by reaching out to us via email or WhatsApp. We\'ll discuss your needs and recommend the best services for your situation.' },
        { q: 'What is your response time?', a: 'We typically respond to all inquiries within 24 hours during business hours (Monday-Friday, 9 AM-6 PM WAT).' },
      ],
    },
    {
      category: 'Services',
      items: [
        { q: 'What services do you offer?', a: 'We offer Digital Tools & Automation, Branding & Creative Services, AI Guidance & Training, Business Setup & Systems, and NIOEZE Academy.' },
        { q: 'Can I use multiple services?', a: 'Absolutely! Many clients use multiple services in combination to achieve their goals. We can create a custom package for your needs.' },
        { q: 'Do you offer custom solutions?', a: 'Yes, we specialize in tailored solutions. Contact us to discuss your specific requirements.' },
      ],
    },
    {
      category: 'Pricing',
      items: [
        { q: 'How is pricing structured?', a: 'Pricing varies by service and scope. We provide transparent quotes after understanding your needs.' },
        { q: 'Do you offer discounts?', a: 'We offer flexible pricing options and special rates for long-term partnerships and group engagements.' },
        { q: 'Is there a free consultation?', a: 'Yes, we offer an initial consultation to understand your needs and recommend appropriate services.' },
      ],
    },
    {
      category: 'Academy',
      items: [
        { q: 'How long are the modules?', a: 'Module duration varies from 4 to 12 weeks depending on complexity and depth. Check individual modules for specifics.' },
        { q: 'Is there a certificate after completion?', a: 'Yes, you\'ll receive a certificate of completion after successfully finishing a module.' },
        { q: 'Can I work at my own pace?', a: 'Yes, our academy modules are designed to be flexible, allowing you to progress at your own pace.' },
      ],
    },
    {
      category: 'Support',
      items: [
        { q: 'How do I get support?', a: 'Contact us via email at nioeze@yahoomail.com or through WhatsApp for immediate assistance.' },
        { q: 'What if I have a technical issue?', a: 'Our technical support team is available to help. Describe your issue and we\'ll guide you through resolution.' },
        { q: 'Is there a refund policy?', a: 'Please contact us directly to discuss our refund and cancellation policies for your specific service.' },
      ],
    },
  ];

  return (
    <div>
      <h1>❓ Frequently Asked Questions</h1>
      <p>Find answers to common questions about NIOEZE services, pricing, and support.</p>

      {faqCategories.map((categoryData, categoryIndex) => (
        <div key={categoryIndex}>
          <h2>{categoryData.category}</h2>
          {categoryData.items.map((item, itemIndex) => {
            const globalIndex = categoryIndex * 100 + itemIndex;
            return (
              <div key={itemIndex} style={{ border: '1px solid #e5e7eb', borderRadius: '0.5rem', marginBottom: '1rem', overflow: 'hidden' }}>
                <div style={{ backgroundColor: '#f3f4f6', padding: '1rem', cursor: 'pointer', userSelect: 'none' }} onClick={() => toggleItem(globalIndex)}>
                  <h3 style={{ margin: 0, display: 'flex', justifyContent: 'space-between', alignItems: 'center', color: '#003d82' }}>
                    {item.q}
                    <span style={{ marginLeft: '1rem' }}>{openItems.includes(globalIndex) ? '−' : '+'}</span>
                  </h3>
                </div>
                {openItems.includes(globalIndex) && (
                  <div style={{ padding: '1rem', backgroundColor: '#ffffff', borderTop: '1px solid #e5e7eb' }}>
                    <p>{item.a}</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      ))}

      <h2>Still Have Questions?</h2>
      <p>Didn't find your answer? Contact us directly:</p>
      <ul>
        <li>Email: <a href="mailto:nioeze@yahoomail.com">nioeze@yahoomail.com</a></li>
        <li>WhatsApp: Available on request</li>
        <li>Response time: Within 24 hours</li>
      </ul>
    </div>
  );
}
```

