    border-bottom: 1px solid #e5e7eb;
    padding: 1.5rem;
  }

  .docs-content {
    margin-left: 0;
    padding: 1rem;
  }

  .docs-main {
    padding: 1rem;
  }

  .docs-main h1 {
    font-size: 1.75rem;
  }

  .docs-main h2 {
    font-size: 1.25rem;
  }

  .nav-submenu {
    display: none;
  }
}

@media (max-width: 640px) {
  .docs-main {
    padding: 0.75rem;
