interface DocCardProps {
  title: string;
  description: string;
  icon?: string;
  link?: string;
}

export default function DocCard({ title, description, icon, link }: DocCardProps) {
  const content = (
    <>
      <div className="doc-card-title">{icon && `${icon} `}{title}</div>
      <div className="doc-card-description">{description}</div>
    </>
  );

  if (link) {
    return (
      <a href={link} style={{ textDecoration: 'none', color: 'inherit' }}>
        <div className="doc-card">{content}</div>
      </a>
    );
  }

  return <div className="doc-card">{content}</div>;
}
